-- ----------------------------
-- Table structure for mc_generation_log
-- ----------------------------
DROP TABLE IF EXISTS `mc_generation_log`;
CREATE TABLE `mc_generation_log`  (
  `log_id` bigint NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `task_id` bigint NULL DEFAULT NULL COMMENT '任务ID',
  `user_id` bigint NULL DEFAULT NULL COMMENT '用户ID',
  `username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名',
  `style_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '用户输入的风格描述',
  `optimized_prompt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '优化后的提示词',
  `generated_image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '生成的图片URL',
  `text_model_id` bigint NULL DEFAULT NULL COMMENT '文本模型ID',
  `image_model_id` bigint NULL DEFAULT NULL COMMENT '图像模型ID',
  `text_model_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文本模型名称',
  `image_model_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '图像模型名称',
  `generation_time` int NULL DEFAULT NULL COMMENT '生成耗时（秒）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '状态（0失败 1成功）',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '错误信息',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`log_id`) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 275 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'AI生成调用日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of mc_generation_log
-- ----------------------------

-- ----------------------------
-- Table structure for mc_generation_task
-- ----------------------------
DROP TABLE IF EXISTS `mc_generation_task`;
CREATE TABLE `mc_generation_task`  (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `task_no` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '任务编号',
  `generated_image_url` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '鐢熸垚鐨勫師濮嬪ぇ鍥綰RL',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `user_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '用户名',
  `version_id` bigint NULL DEFAULT NULL COMMENT 'MC版本',
  `version_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '版本名称',
  `template_id` bigint NULL DEFAULT NULL COMMENT '模板ID',
  `style_description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '风格描述',
  `generation_type` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'item' COMMENT '生成类型(item=物品,ui=UI,complete=完整)',
  `pre_prompt` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '预提示词(替换风格前)',
  `optimized_prompt` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '优化后的提示词(Gemini 2.5 Pro生成)',
  `final_prompt` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '最终提示词',
  `text_model_id` bigint NULL DEFAULT NULL COMMENT '文本模型ID',
  `text_model_url` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '文本模型URL',
  `image_model_id` bigint NULL DEFAULT NULL COMMENT '画图模型ID',
  `image_model_url` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '画图模型URL',
  `image_url` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'AI生成的图片URL',
  `task_status` tinyint NULL DEFAULT 0 COMMENT '任务状态(0待处理 1生成中 2预处理中 3切割中 4完成 5失败)',
  `total_textures` int NULL DEFAULT 0 COMMENT '总材质数',
  `completed_textures` int NULL DEFAULT 0 COMMENT '已完成数',
  `cost_points` int NULL DEFAULT 100 COMMENT '消耗积分',
  `error_msg` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '错误信息',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `complete_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `material_type` tinyint NULL DEFAULT 1 COMMENT '材质类型(1:物品材质 2:UI材质)',
  PRIMARY KEY (`task_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_task_status`(`task_status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 209 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '生成任务表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of mc_generation_task
-- ----------------------------

-- ----------------------------
-- Table structure for mc_pack_export
-- ----------------------------
DROP TABLE IF EXISTS `mc_pack_export`;
CREATE TABLE `mc_pack_export`  (
  `export_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `task_id` bigint NULL DEFAULT NULL,
  `pack_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '材质包名称',
  `pack_description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '材质包描述',
  `pack_cover` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '封面图片路径',
  `mc_version_id` bigint NULL DEFAULT NULL COMMENT 'MC版本ID',
  `texture_count` int NULL DEFAULT NULL COMMENT '包含材质数',
  `file_path` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'ZIP文件路径',
  `file_size` bigint NULL DEFAULT NULL COMMENT '文件大小',
  `download_count` int NULL DEFAULT 0,
  `create_time` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`export_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '材质包导出记录表' ROW_FORMAT = DYNAMIC;

