-- ----------------------------
-- Table structure for mc_pack_upload
-- ----------------------------
DROP TABLE IF EXISTS `mc_pack_upload`;
CREATE TABLE `mc_pack_upload`  (
  `upload_id` bigint NOT NULL AUTO_INCREMENT COMMENT '上传ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `user_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '用户名',
  `pack_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '材质包名称',
  `original_file_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '原始文件名',
  `file_path` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'ZIP文件路径',
  `file_size` bigint NULL DEFAULT NULL COMMENT '文件大小',
  `mc_version` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '检测到的MC版本',
  `pack_format` int NULL DEFAULT NULL COMMENT 'pack_format值',
  `texture_count` int NULL DEFAULT NULL COMMENT '材质数量',
  `file_structure` json NULL COMMENT '文件结构树',
  `parse_status` tinyint NULL DEFAULT 0 COMMENT '解析状态(0待解析 1成功 2失败)',
