-- ----------------------------
-- Table structure for mc_payment_order
-- ----------------------------
DROP TABLE IF EXISTS `mc_payment_order`;
CREATE TABLE `mc_payment_order`  (
  `order_id` bigint NOT NULL AUTO_INCREMENT,
  `out_trade_no` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '商户订单号',
  `trade_no` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '支付平台订单号',
  `user_id` bigint NULL DEFAULT NULL COMMENT '用户ID',
  `username` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '用户名',
  `order_type` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'recharge' COMMENT '订单类型（recharge充值/subscription订阅）',
  `package_id` bigint NULL DEFAULT NULL COMMENT '套餐ID（订阅订单使用）',
  `duration_months` int NULL DEFAULT NULL COMMENT '订阅时长（月）',
  `start_time` datetime NULL DEFAULT NULL COMMENT '订阅开始时间',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '订阅到期时间',
  `product_name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '商品名称',
  `amount` decimal(10, 2) NOT NULL COMMENT '支付金额',
  `points` int NULL DEFAULT NULL COMMENT '充值积分数（充值订单使用）',
  `payment_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '支付方式',
  `status` char(1) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '0' COMMENT '订单状态（0待支付 1已支付 2已取消 3已退款）',
  `notify_status` char(1) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '0' COMMENT '通知状态（0未通知 1已通知）',
  `pay_time` datetime NULL DEFAULT NULL,
  `notify_time` datetime NULL DEFAULT NULL COMMENT '通知时间',
  `config_id` bigint NULL DEFAULT NULL COMMENT '支付配置ID',
  `param` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '业务扩展参数',
  `remark` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT NULL,
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`order_id`) USING BTREE,
  UNIQUE INDEX `order_no`(`out_trade_no` ASC) USING BTREE,
  UNIQUE INDEX `idx_out_trade_no`(`out_trade_no` ASC) USING BTREE,
