  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 413 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '积分消费记录表' ROW_FORMAT = DYNAMIC;

