-- Records of mc_user_points
-- ----------------------------

-- ----------------------------
-- Table structure for mc_user_subscription
-- ----------------------------
DROP TABLE IF EXISTS `mc_user_subscription`;
CREATE TABLE `mc_user_subscription`  (
  `subscription_id` bigint NOT NULL AUTO_INCREMENT COMMENT '订阅ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `subscription_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'normal' COMMENT '订阅类型：normal普通用户 diamond钻石订阅用户',
  `package_id` bigint NULL DEFAULT NULL COMMENT '套餐ID，关联mc_subscription_package',
  `start_time` datetime NULL DEFAULT NULL COMMENT '订阅开始时间',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '订阅到期时间，NULL表示永久',
  `is_permanent` tinyint(1) NULL DEFAULT 0 COMMENT '是否永久订阅：0否 1是',
  `last_point_grant_month` varchar(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '上次发放积分的月份，格式：2026-02',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '备注',
  PRIMARY KEY (`subscription_id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_subscription_type`(`subscription_type` ASC) USING BTREE,
  INDEX `idx_expire_time`(`expire_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户订阅信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mc_user_subscription
-- ----------------------------

