  `task_id` bigint NULL DEFAULT NULL,
  `texture_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `original_path` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '原始生成路径',
  `edited_path` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '编辑后路径',
  `is_edited` tinyint(1) NULL DEFAULT 0 COMMENT '是否编辑过',
  `mapping_path` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '映射的材质包路径',
  `create_time` datetime NULL DEFAULT NULL,
  `update_time` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`texture_id`) USING BTREE,
  INDEX `idx_user_task`(`user_id` ASC, `task_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '用户材质管理表' ROW_FORMAT = DYNAMIC;

