-- Table structure for mc_version_naming
-- ----------------------------
DROP TABLE IF EXISTS `mc_version_naming`;
CREATE TABLE `mc_version_naming`  (
  `version_id` bigint NOT NULL AUTO_INCREMENT COMMENT '版本ID',
  `version_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '版本号',
  `naming_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '命名规则JSON',
  `grid_rows` int NULL DEFAULT 5 COMMENT '默认网格行数',
