INSERT INTO `sys_oper_log` VALUES (133, 'AI模型配置', 2, 'com.ruoyi.web.controller.mc.McAiModelController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/model', '127.0.0.1', '内网IP', '{\"apiKey\":\"sk-zynublwdoArVkZVPSn7MQBhfpmJGazTwytz9unqyesTn8MFg\",\"apiUrl\":\"https://aicanapi.com/v1beta/models/gemini-3-pro-image-preview:generateContent\",\"createBy\":\"\",\"createTime\":\"2026-01-26 18:34:49\",\"isActive\":\"1\",\"modelId\":6,\"modelName\":\"gemini-3-pro-image-preview\",\"modelType\":1,\"params\":{},\"status\":\"0\",\"updateBy\":\"\",\"updateTime\":\"2026-01-28 11:58:39\"} ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-28 11:58:38', 26);
INSERT INTO `sys_oper_log` VALUES (134, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-01-27 12:17:39\",\"description\":\"标准黄金模板，用于生成Minecraft材质包的完整提示词。支持49个标准物品，使用[]作为风格占位符。\",\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"ULTIMATE GOLDEN TEMPLATE (Version 8.0 - The Final Mandate on Uniqueness & Purity)\\nMANDATORY TECHNICAL RENDERING SPECIFICATIONS (绝对技术渲染规范):\\n\\nAbsolute Purity & Layout (绝对纯净与布局):\\n\\nBackground: The background for the entire spritesheet MUST be ABSOLUTELY PURE, UNIFORM, SOLID WHITE (#FFFFFF). No exceptions, no gradients, no off-white, no gray. This is the highest priority rendering instruction.\\nOutput Format & Resolution: A single, seamless PNG image, exactly 160px wide by 320px high.\\nSeamless Grid: A perfect 10x5 grid of 49 32x32 pixel sprites. ABSOLUTELY NO visible grid lines, black lines, borders, or spacing between sprites.\\nPerfect Alignment: Each of the 49 item sprites MUST be rendered at 32x32 pixels and PERFECTLY centered in its designated, unalterable grid slot.\\nUniversal Asset Design Rules (通用资产设计法则):\\n\\nRule A: Mandatory Orientation (强制朝向): All tools (Pickaxes, Axes, Shovels) and Swords MUST point towards the top-right.\\nRule B: Pure Pixel Art Style (纯粹像素艺术): Strictly High-fidelity 32x32 pixel art. Clean, crisp outlines and flat color blocking. ABSOLUTELY NO light effects, glow, bloom, or shimmer.\\nTHE CREATIVE MANDATE (最高创意指令):\\n\\nA. 深度概念重塑 (Deep Conceptual Re-imagination): 必须从根本上重新思考每个物品在 [THE NEW THEME\'s] 世界观下的身份。将“金苹果”重塑为“仙班寿桃”，将“铁锭”重塑为“玄铁”。\\nB. 形状与文化符号融合 (Form & Cultural Symbol Fusion): 物品的形状本身必须改变，以融合主题的标志性符号。例如，中国风的Gold Ingot 必须是‘元宝’形状。\\nC. 材质的文化转译 (Cultural Translation of Materials): 基础材质的名称和质感必须被主题文化所同化。例如，中国风的Diamond 必须被描述为‘寒玉’。\\nD. Principle of Unique Identity (唯一性原则): 这是新增的绝对规则。 每个物品的核心创意概念必须是独一无二的。\\n强制标准: 如果“末影珍珠”被重塑为“混沌骰子”，那么整个材质包中任何其他物品都绝对不能再是骰子。\\n强制标准: 如果“药水”被重塑为“葫芦”，那么任何其他物品都不能再是葫芦。\\n此规则强制确保每个物品都有自己鲜明的、不可替代的身份，杜绝任何形式的创意复用。\\nItem List & Stylization (The Core Task):\\n\\nYou will use the FIXED 49-item list below.\\nFor EACH of the 49 items, you must invent a cre', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-28 12:50:31', 31);
