INSERT INTO `sys_oper_log` VALUES (154, 'MC预提示词模板', 1, 'com.ruoyi.web.controller.mc.McPromptTemplateController.add()', 'POST', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-02 13:36:56\",\"description\":\"2026.2.2\",\"isActive\":\"0\",\"params\":{},\"status\":\"0\",\"templateContent\":\"\\nULTIMATE GOLDEN TEMPLATE (Version 12.0 - The Final Mandate on PURE IMAGERY & Orientation)\\nMANDATORY TECHNICAL RENDERING SPECIFICATIONS (绝对技术渲染规范):\\n\\nAbsolute Purity & Layout (绝对纯净与布局):\\n\\nBackground: The background MUST be ABSOLUTELY PURE, UNIFORM, SOLID WHITE (#FFFFFF).\\nOutput Format & Resolution: A single, seamless PNG image, exactly 160px wide by 320px high.\\nSeamless Grid: A perfect 10x5 grid of 49 32x32 pixel sprites. ABSOLUTELY NO visible grid lines, borders, or spacing.\\nPerfect Alignment: Each sprite MUST be 32x32 pixels and PERFECTLY centered in its slot.\\nUniversal Asset Design Rules (通用资产设计法则):\\n\\nRule A: Mandatory Orientation (强制朝向 - 已修正):\\nPickaxes and Shovels MUST have their heads pointing towards the top-right.\\nCRITICAL: The primary cutting edge of all Swords and Axes MUST face towards the top-left. This applies to all bladed weapons, including straight swords, curved scimitars, and axes of any shape.\\nRule B: Strict Pixel Art Aesthetic (严格的像素美学):\\nThe style is strictly crisp pixel art, with clean edges and hard pixel boundaries.\\nAll coloring MUST use solid color blocks with sharp contrast between colors.\\nno anti-aliasing and no gradient or dithering are permitted.\\nRule C: ABSOLUTE PROHIBITION OF ALL TEXT (绝对禁止所有文字 - 已强化):\\nThis is a non-negotiable core rule. The final generated image MUST contain ZERO text, letters, numbers, characters, calligraphy, or any form of writing.\\nCRITICAL INSTRUCTION ON REFERENCE IMAGES (关键指令): Analyze any provided reference images for visual style, color palette, and creative concepts ONLY. You are EXPLICITLY FORBIDDEN from reading, interpreting, or replicating any text, labels, or annotations. Treat all text as if it were invisible or corrupted data. The final output must be 100% PURE VISUAL ART.\\nTHE CREATIVE MANDATE (最高创意指令):\\n\\nA. RADICAL TRANSFORMATION (彻底重塑): 彻底抛弃原版Minec', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-02 13:36:57', 21);
