INSERT INTO `sys_oper_log` VALUES (273, 'MC预提示词模板', 1, 'com.ruoyi.web.controller.mc.McPromptTemplateController.add()', 'POST', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-05 18:29:24\",\"isActive\":\"0\",\"params\":{},\"status\":\"0\",\"templateContent\":\"ULTIMATE GOLDEN TEMPLATE (Version 9.0 - Vertical Purity Edition)\\n\\nMANDATORY TECHNICAL RENDERING SPECIFICATIONS:\\n\\n1. Absolute Purity & Vertical Layout:\\n   - Canvas Orientation: VERTICAL / PORTRAIT MODE.\\n   - Background: The background for the entire spritesheet MUST be ABSOLUTELY PURE, UNIFORM, SOLID WHITE (#FFFFFF). No exceptions, no gradients, no off-white, no gray.\\n   - Output Format & Resolution: A single, seamless PNG image, exactly 160px wide by 320px high (Aspect Ratio 1:2).\\n   - Seamless Grid: A perfect 5 columns x 10 rows grid of 50 32x32 pixel sprites. \\n   - Strict Separation: ABSOLUTELY NO visible grid lines, black lines, borders, frames, or spacing between sprites.\\n   - Perfect Alignment: Each of the 50 item sprites MUST be rendered at 32x32 pixels and PERFECTLY centered in its designated, unalterable grid slot.\\n   - ZERO TEXT POLICY: There must be ABSOLUTELY NO text, no letters, no numbers, no labels, no watermarks, and no annotations on the image. The output must contain ONLY the raw pixel art items.\\n\\n2. Universal Asset Design Rules:\\n   - Rule A: Mandatory Orientation: All tools (Pickaxes, Axes, Shovels) and Swords MUST point towards the top-right.\\n   - Rule B: Pure Pixel Art Style: Strictly High-fidelity 32x32 pixel art. Clean, crisp outlines and flat color blocking. NO light effects, glow, bloom, or shimmer.\\n\\nTHE CREATIVE MANDATE:\\n\\nA. Deep Conceptual Re-imagination: You must fundamentally rethink the identity of each item within the specific worldview of the theme.\\nB. Form & Cultural Symbol Fusion: The shape of the items themselves must change to incorporate iconic symbols of the theme.\\nC. Cultural Translation of Materials: The textures and visual properties of base materials (wood, stone, iron, diamond) must be assimilated by the theme\'s visual culture.\\nD. Principle of Unique Identity: The core creative concept of ea', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-05 18:29:23', 74);
