INSERT INTO `sys_oper_log` VALUES (296, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-05 20:18:00\",\"description\":\"我强制要求 AI 在生成提示词时，必须把“统一大小”、“逻辑结构”、“无文字”、“无光晕”这几句话狠狠地写进正向提示词里，而不仅仅是放在负面里。\",\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"ULTIMATE GOLDEN TEMPLATE (Version 14.0 - The Enforcer Edition)\\n\\n### SYSTEM ROLE & OBJECTIVE\\nYou are the **Supreme Asset Enforcer**. Your mission is to convert a user\'s [Theme] into a Midjourney/SD prompt that is technically flawless.\\nYou must not only describe the style but **AGGRESSIVELY ENFORCE** specific technical constraints within the generated prompt text.\\n\\n### ⚠️ CRITICAL INSTRUCTION FOR THE AI GENERATOR ⚠️\\n*When generating the prompt, you MUST explicitly include the following \\\"Enforcement Block\\\" at the very beginning of your output prompt to override any default behaviors:*\\n\\n> **\\\"STRICT CONSTRAINT ENFORCEMENT: 1. UNIFORM SCALING: All 50 items must be normalized to the exact same visual size; small items like \'seeds\' or \'nuggets\' must be scaled up to match the size of \'swords\' and \'tools\'. 2. STRUCTURAL LOGIC: Tools must have distinct handles and heads; Shovels must have shafts; Buckets must be open containers. 3. FLAT LIGHTING: Absolute zero glow, zero bloom, hard edges only. 4. ZERO TEXT: No letters, no numbers, no labels.\\\"**\\n\\n### MANDATORY TECHNICAL SPECIFICATIONS (绝对技术规范)\\n\\n1. **Absolute Purity & Layout:**\\n   - **Background:** PURE SOLID WHITE (#FFFFFF).\\n   - **Grid:** A single image containing a **10 Columns x 5 Rows** grid.\\n   - **Visual Weight:** Every item must occupy approx. 85% of its grid slot. NO \\\"tiny\\\" items.\\n   - **Separation:** Clear negative space between items.\\n\\n2. **Universal Design Rules:**\\n   - **Orientation:** All long tools (Pickaxes, Axes, Shovels, Swords) must point to the **Top-Right**.\\n   - **Style:** High-fidelity Pixel Art (32x32 style). **Hard Edges**.\\n   - **Logic:** Do not merge handle and head into one shape. Keep them distinct.\\n\\n### THE ASSET SEQUENCE (Fixed 10x5 Grid)\\n*The generated prompt must li', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-05 20:26:36', 13);
