INSERT INTO `sys_oper_log` VALUES (305, '材质生成', 1, 'com.ruoyi.web.controller.mc.McGenerationController.add()', 'POST', 1, 'gqy', NULL, '/mc/generate', '127.0.0.1', '内网IP', '{\"costPoints\":100,\"createTime\":\"2026-02-05 20:57:57\",\"imageModelId\":2,\"params\":{},\"startTime\":\"2026-02-05 20:57:57\",\"styleDescription\":\"角斗场冠军，网斗士的三叉戟、带刺的拳套、罗马竞技场\",\"taskId\":50,\"taskNo\":\"TASK_1770296277848\",\"taskStatus\":1,\"templateId\":1,\"textModelId\":1,\"userId\":100,\"userName\":\"gqy\",\"versionId\":1} ', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"costPoints\":100,\"createTime\":\"2026-02-05 20:57:57\",\"imageModelId\":2,\"params\":{},\"startTime\":\"2026-02-05 20:57:57\",\"styleDescription\":\"角斗场冠军，网斗士的三叉戟、带刺的拳套、罗马竞技场\",\"taskId\":50,\"taskNo\":\"TASK_1770296277848\",\"taskStatus\":1,\"templateId\":1,\"textModelId\":1,\"userId\":100,\"userName\":\"gqy\",\"versionId\":1}}', 0, NULL, '2026-02-05 20:57:57', 45);
INSERT INTO `sys_oper_log` VALUES (306, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-05 20:18:00\",\"description\":\"我强制要求 AI 在生成提示词时，必须把“统一大小”、“逻辑结构”、“无文字”、“无光晕”这几句话狠狠地写进正向提示词里，而不仅仅是放在负面里。\",\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"ULTIMATE GOLDEN TEMPLATE (Version 15.0 - The Conceptual Rebirth & Anti-Vanilla Edition)\\n\\n### SYSTEM ROLE & OBJECTIVE\\nYou are the **Supreme Conceptual Architect**. Your goal is to erase \\\"Vanilla Minecraft\\\" from the visual output and replace it entirely with the user\'s [Theme].\\n\\n### ⚠️ ABSOLUTE FORBIDDEN ZONE (CRITICAL) ⚠️\\n1.  **NO VANILLA SHAPES:** It is strictly FORBIDDEN to generate items that look like the default Minecraft textures.\\n    -   *Example:* An \\\"Apple\\\" must NOT look like a red fruit if the theme doesn\'t allow it. In a \\\"Cyberpunk\\\" theme, an \\\"Apple\\\" must be a \\\"Red Health Canister\\\".\\n    -   *Example:* An \\\"Ender Pearl\\\" must NOT be a green ball. It must be reimagined (e.g., a \\\"Teleportation Rune\\\", a \\\"Void Gadget\\\", or a \\\"Mechanical Eye\\\").\\n2.  **NO TEXT / NO GLOW:** As always, Zero Typography, Zero Bloom, Hard Edges only.\\n\\n### INSTRUCTIONS FOR THE AI GENERATOR\\n*When generating the prompt, you MUST explicitly include the following \\\"Concept Enforcement Block\\\" at the very beginning:*\\n\\n> **\\\"STRICT CONCEPTUAL & TECHNICAL ENFORCEMENT: 1. TOTAL REDESIGN: Do not use default Minecraft shapes. All items must be visually reimagined to fit the theme (e.g., Pearl = Tech Device/Magical Artifact, not a ball). 2. UNIFORM SCALING: All 50 items must be normalized to the exact same visual size. 3. FLAT LIGHTING: Zero glow, zero bloom, hard edges only. 4. ZERO TEXT.\\\"**\\n\\n### MANDATORY TECHNICAL SPECIFICATIONS\\n1.  **Background:** PURE SOLID WHITE (#FFFFFF).\\n2.  **Layout:** 10 Columns x 5 Rows (50 items total).\\n3.  **Visual Weight:** All items (from swords to seeds) must be **EQUAL SIZE** (approx 85% of grid slot).\\n\\n### THE ASSET TRANSLATION (How to describe the items)\\n*You must interpret the items creatively. Do not just list their names; ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-05 21:11:32', 20);
