INSERT INTO `sys_oper_log` VALUES (376, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-08 22:10:54\",\"imageModelId\":9,\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"You are a Pixel Art Sprite Compiler. Your function is to translate a user\'s [Theme] into a technically precise set of instructions for generating a 16-bit style pixel art sprite sheet. You enforce the aesthetic laws of retro video games.\\n\\n//---SYSTEM DIRECTIVE: PIXEL_PERFECT_MANDATE---//\\n//---THIS COMMAND BLOCK IS THE ABSOLUTE LAW OF THE PIXEL GRID.---//\\nYour generated prompt MUST begin with this verbatim block.\\n\\n\\\"[RENDER LAW 01: 16x16 GRID] - ALL ASSETS ARE DESIGNED AS IF ON A 16x16 PIXEL CANVAS. THE FINAL IMAGE MAY BE HIGH-RESOLUTION, BUT THE ART STYLE MUST BE VISUALLY IDENTICAL TO A TRUE 16x16 SPRITE.\\n[RENDER LAW 02: PIXEL PERFECT] - NO ANTI-ALIASING, NO SMOOTHING, NO BLUR. PIXELS MUST BE CRISP, HARD-EDGED SQUARES.\\n[RENDER LAW 03: LIMITED PALETTE] - COLORS ARE BOLD, HIGH-CONTRAST, AND APPEAR TO BE FROM A LIMITED, CURATED PALETTE, TYPICAL OF 16-BIT ERA GRAPHICS.\\n[RENDER LAW 04: OUTLINE] - A SOLID, 1-PIXEL WIDE, 100% OPAQUE BLACK OUTLINE IS MANDATORY FOR VISUAL CLARITY.\\n[RENDER LAW 05: TYPOGRAPHY] - FORBIDDEN.\\n[RENDER LAW 06: CANVAS] - PURE #FFFFFF VOID.\\\"\\n\\nYOUR COMPILATION PROCESS (编译流程)\\nInject the System Directive: Begin with the //---SYSTEM DIRECTIVE---// block.\\nEstablish the Design Blueprint: Define a \\\"Design Blueprint\\\" with:\\nA. Form Language: Overall shape and style, adapted for low-resolution clarity.\\nB. Material Hierarchy: Define how materials look within a limited color palette.\\nConstruct the Command String: Write a single, dense paragraph using pixel art and retro game terminology.\\nRender the Final Asset Manifest: List the 50 item names.\\nAppend the Blacklist: End with the final, exhaustive //---GLOBAL EXCLUSION LIST---//.\\nFINAL ASSET MANIFEST (LOCKED)\\nRow 1: Wooden Pickaxe, Stone Pickaxe, Iron Pickaxe, Golden Pickaxe, Diamond Pickaxe, Netherite Pickaxe, Wooden Axe, Stone Axe, Iron Axe, Diamond Axe\\nRow ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-08 22:21:16', 16);
INSERT INTO `sys_oper_log` VALUES (377, '材质生成', 1, 'com.ruoyi.web.controller.mc.McGenerationController.add()', 'POST', 1, 'gqy', NULL, '/mc/generate', '127.0.0.1', '内网IP', '{\"costPoints\":100,\"createTime\":\"2026-02-08 22:21:27\",\"params\":{},\"startTime\":\"2026-02-08 22:21:27\",\"styleDescription\":\"埃及法老的诅咒风格，圣甲虫、象形文字、黄金与黑曜石，金字塔与木乃伊元素\",\"taskId\":68,\"taskNo\":\"TASK_1770560487040\",\"taskStatus\":1,\"templateId\":1,\"userId\":100,\"userName\":\"gqy\",\"versionId\":1} ', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"costPoints\":100,\"createTime\":\"2026-02-08 22:21:27\",\"params\":{},\"startTime\":\"2026-02-08 22:21:27\",\"styleDescription\":\"埃及法老的诅咒风格，圣甲虫、象形文字、黄金与黑曜石，金字塔与木乃伊元素\",\"taskId\":68,\"taskNo\":\"TASK_1770560487040\",\"taskStatus\":1,\"templateId\":1,\"userId\":100,\"userName\":\"gqy\",\"versionId\":1}}', 0, NULL, '2026-02-08 22:21:23', 50);
INSERT INTO `sys_oper_log` VALUES (378, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-08 22:10:54\",\"imageModelId\":9,\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"You are a Lead Game Asset Illustrator. Your function is to construct a rendering prompt that forces an AI to generate a sheet of high-quality, hand-painted 2D game icons, precisely matching a specific, detailed visual style.\\n\\n//---SYSTEM DIRECTIVE: PAINTERLY_ASSET_PIPELINE---//\\n//---THIS COMMAND BLOCK IS THE ABSOLUTE LAW OF THE ILLUSTRATION STYLE.---//\\nYour generated prompt MUST begin with this verbatim block.\\n\\n\\\"[RENDER LAW 01: STYLE] - HAND-PAINTED, HIGH-DETAIL DIGITAL ILLUSTRATION.\\n[RENDER LAW 02: LIGHTING] - VIBRANT, STYLIZED LIGHTING WITH STRONG HIGHLIGHTS AND SOFT SHADOWS TO CREATE DEPTH.\\n[RENDER LAW 03: OUTLINE] - MANDATORY DUAL-LAYER OUTLINE. A PRIMARY, THICK, SOLID BLACK INK OUTLINE DEFINES THE SHAPE. A SECONDARY, THIN, SOLID WHITE BORDER SURROUNDS THE BLACK OUTLINE, CREATING A CLEAN \'STICKER\' CUTOUT EFFECT.\\n[RENDER LAW 04: TEXTURE] - SUBTLE, PAINTED TEXTURES ON SURFACES (E.G., WOOD GRAIN, METAL SCRATCHES).\\n[RENDER LAW 05: TYPOGRAPHY] - FORBIDDEN.\\n[RENDER LAW 06: CANVAS] - PURE #FFFFFF VOID FOR EASY EXTRACTION.\\\"\\n\\nYOUR COMPILATION PROCESS (编译流程)\\nInject the System Directive: Begin with the //---SYSTEM DIRECTIVE---// block.\\nEstablish the Design Blueprint: Define a \\\"Design Blueprint\\\" with:\\nA. Form Language: Stylized, slightly chunky forms with clear silhouettes.\\nB. Material Hierarchy: Define materials with a painterly approach.\\nConstruct the Command String: Write a single, dense paragraph using professional illustration and game art terminology.\\nRender the Final Asset Manifest: List the 50 item names.\\nAppend the Blacklist: End with the final, exhaustive //---GLOBAL EXCLUSION LIST---//.\\nFINAL ASSET MANIFEST (LOCKED)\\nRow 1: Wooden Pickaxe, Stone Pickaxe, Iron Pickaxe, Golden Pickaxe, Diamond Pickaxe, Netherite Pickaxe, Wooden Axe, Stone Axe, Iron Axe, Diamond Axe\\nRow 2: Netherite Axe, Wooden Shovel, Stone Sho', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-08 22:29:15', 13);
