INSERT INTO `sys_oper_log` VALUES (382, '公告', 2, 'com.ruoyi.web.controller.mc.McAnnouncementController.edit()', 'PUT', 1, 'admin', '研发部门', '/mc/announcement', '127.0.0.1', '内网IP', '{\"announcementId\":1,\"content\":\"尊敬的用户：\\n欢迎使用【材质工坊】—— 专注于《我的世界》（Minecraft）AI 生图材质包定制的专业工具平台！目前网站已全面实现 AI 智能生成、风格自定义、分辨率调节、元素组合编辑、一键导出等核心功能，同时提供《我的世界》原版材质包官方源下载服务，旨在为玩家提供高效、规范的材质包创作支持，助力大家打造独具特色的游戏视觉体验。\\n为严格遵守《我的世界》官方用户协议（EULA）、开发者文明守则及相关知识产权保护规定，保障平台合规运营，保护 Mojang Studios 及相关权利人的合法权益，现发布专项禁令公告，所有用户必须严格遵守以下规则，严禁任何违反《我的世界》官方规定及平台使用准则的行为：\\n一、核心禁令条款（严禁以下行为）\\n严禁侵权复刻原版素材：不得通过平台 AI 生图功能生成、导出与《我的世界》原版（官方默认）材质包实质相似的内容，包括但不限于：\\n复制或高度模仿原版方块、道具、角色、界面的纹理细节、色彩体系、造型比例、像素风格等核心视觉元素；\\n复刻原版材质包中的 UI 设计（如 16×16 像素图标、背包 3×9 布局、合成表 3×3 网格等）、字体样式（含 Minecraftia 及近似等宽像素字体）、HUD 元素位置比例等受著作权保护的内容；\\n变相复刻原版材质包的整体风格、元素组合逻辑，导致与原版产生混淆。\\n严禁逆向提取原版材质：用户通过本平台下载的《我的世界》原版材质包，仅可用于参考材质包的标准命名规范（如方块 / 物品文件名格式）与文件夹结构布局（如 assets/minecraft/textures 的层级规范），严禁以任何技术手段进行逆向解析、提取、导出原版材质包中的纹理文件、元数据等核心资源，包括但不限于：\\n使用解压工具、反编译软件拆解原版材质包压缩文件，提取内部.png 纹理素材、.json 配置文件等；\\n通过截图、录屏、像素采样等方式获取原版材质的视觉信息并用于 AI 生成训练或直接复用；\\n将原版材质包的核心资源用于非创作参考的其他用途，或传播、分享提取的原版素材。\\n严禁违规使用 IP 与商业变现：\\n未经 Mojang 官方明确授权，不得将生成的材质包用于商业用途（包括售卖、广告引流、付费分享等），不得利用《我的世界》品牌名称、Logo、商标进行盈利活动；\\n不得将生成的材质包冒充官方出品，或误导他人认为其与《我的世界》官方存在关联。\\n严禁抄袭他人原创组件：不得通过 AI 生图功能抄袭、盗用其他开发者已发布的材质包原创内容，包括独创的艺术风格、设计元素、素材组合等，避免出现原创性与功能性不足的同质化作品。\\n严禁规避官方规则与法律风险：不得采取任何技术手段或刻意调整（如轻微改色、微调细节）规避上述禁令，不得生成违反《我的世界》官方协议、知识产权法及相关法律法规的其他内容。\\n二、禁令法律依据与核心目的\\n依据《我的世界》官方用户协议，Mojang AB（微软旗下）拥有游戏及相关内容的完整知识产权，包括方块纹理、UI 设计、品牌标识等核心资源，未经授权的复刻、逆向提取、商用行为均属违约违法行为；\\n依据《中华人民共和国著作权法》，游戏素材、艺术设计等受法律保护，实质性相似的模仿、未经许可的提取使用可被判定为侵权，平台提供原版材质包下载仅为创作规范参考，不代表授予任何资源使用授权；\\n核心目的：保障平台合规运营，规避法律风险；保护知识产权方及原创开发者权益；明确原版材质包的合法使用边界，杜绝原材质流出风险；鼓励用户充分利用平台 AI 功能，创作差异化、原创性材质包，共建健康创作环境。\\n三、违规处理机制\\n平台将通过 AI 智能检测（比对原版素材库及侵权特征）+ 人工复核 + 下载行为监测的三重机制，对用户操作及生成内容进行合规审查，违规处理如下：\\n首次违规（含轻度逆向尝试、生成类原版素材）：系统自动拦截导出 / 提取操作，发送违规警示通知，明确整改要求，账号功能暂不受限；\\n二次违规：限制账号 AI 生成、导出及原版材质包下载功能 48-72 小时，清空违规生成 / 提取记录，要求提交合规承诺；\\n三次及以上违规 / 恶意违规（含批量提取原版材质、传播侵权素材、商用侵权内容）：永久封禁账号所有功能，删除全部违规关联数据，情节严重者将向 Mojang 官方及相关执法部门报备，并保留追究法律责任的权利。\\n四、合规创作指引\\n充分利用平台 “风格自定义” 功能，选择国风、赛博朋克、写实、奇幻等差异化风格，重构材质包视觉体系，与原版风格形成明显区分；\\n参考原版材质包时，仅用于确认文件命名格式（如 diamond_block.png）与文件夹层级（assets/minecraft/textures/block），不得', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-02-09 11:01:33', 27);
