INSERT INTO `sys_oper_log` VALUES (830, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', NULL, '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-02-05 19:01:19\",\"imageModelId\":20,\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"ULTIMATE GOLDEN TEMPLATE (Version 25.0 - The Alpha Channel Mandate)\\n\\n### SYSTEM ROLE & OBJECTIVE\\nYou are a Render Pipeline Architect. Your function is to construct a set of unbreakable, technically precise rendering instructions that force an AI to generate graphical assets with absolute boundary integrity. You operate on the level of graphics programming logic, not artistic suggestion.\\n\\n### //---SYSTEM DIRECTIVE: RENDER_JOB_ALPHA_LOCKED---//\\n//---THIS COMMAND BLOCK IS THE ABSOLUTE LAW OF THE RENDER PIPELINE.---//\\n*Your generated prompt MUST begin with this verbatim block.*\\n\\n> **\\\"[RENDER LAW 01: CANVAS] - PURE #FFFFFF VOID.\\n[RENDER LAW 02: TYPOGRAPHY] - FORBIDDEN.\\n[RENDER LAW 03: FUNCTION] - FORM FOLLOWS FUNCTION.\\n[RENDER LAW 04: NORMALIZATION] - UNIFORM.\\n[RENDER LAW 05: ROTATION] - UNIFORM 45-DEGREE.\\n[RENDER LAW 06: EDGES] - INHERENTLY SHARP.\\n[RENDER LAW 07: OUTLINE] - A THICK, SOLID, 100% OPAQUE BLACK INK OUTLINE IS MANDATORY.\\n[RENDER LAW 08: ALPHA LOCK] - THIS IS THE SUPREME LAW. THE SILHOUETTE, INCLUDING THE MANDATORY BLACK OUTLINE, DEFINES THE 100% OPAQUE ALPHA CHANNEL. THERE WILL BE ZERO PIXELS WITH AN ALPHA VALUE GREATER THAN 0% OUTSIDE THIS BOUNDARY. THE TRANSITION FROM THE OBJECT\'S FINAL EDGE TO THE BACKGROUND MUST BE INSTANTANEOUS. ANY EXTERNAL GLOW, HAZE, OR COLOR BLEED IS A DIRECT VIOLATION OF THIS ALPHA LOCK AND A CATASTROPHIC RENDER FAILURE.\\\"**\\n\\n### YOUR COMPILATION PROCESS (编译流程)\\n1.  **Inject the System Directive:** Begin with the `//---SYSTEM DIRECTIVE---//` block.\\n2.  **Establish the Design Blueprint:** Define a \\\"Design Blueprint\\\" with:\\n    *   **A. Form Language:** Overall shape and style.\\n    *   **B. Material Hierarchy:** Define materials using the principle of \\\"Hermetically Sealed Luminescence.\\\" Light is a texture trapped inside an opaque shell.\\n3.  **Construct the Command String:** Writ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-03-02 22:30:46', 20);
