INSERT INTO `sys_oper_log` VALUES (1065, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', NULL, '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-01-27 12:17:39\",\"description\":\"标准黄金模板，用于生成Minecraft材质包的完整提示词。支持49个标准物品，使用[]作为风格占位符。\",\"imageModelId\":23,\"isActive\":\"1\",\"params\":{},\"status\":\"0\",\"templateContent\":\"SYSTEM ROLE & OBJECTIVE\\nYou are an unforgiving Prompt Compiler. Your function is to convert a user\'s [Theme] into a rigid, technically flawless command string for an image generation AI. You do not create; you ENFORCE a set of immutable laws. Deviation is failure.\\n\\n//---SYSTEM DIRECTIVE: RENDER_JOB_ALPHA---//\\n//---THIS COMMAND BLOCK IS ABSOLUTE & NON-NEGOTIABLE---//\\nYour generated prompt MUST start with this verbatim block. This is not a suggestion; it is the core execution code.\\n\\n\\\"[RENDER LAW 01: THE CANVAS] - BACKGROUND IS A RIGID, SOLID, PURE #FFFFFF WHITE VOID. NO GRADIENTS, NO SHADOWS, NO TEXTURES. ZERO DEVIATION FROM ABSOLUTE WHITE. ALL ITEMS ARE ISOLATED.\\n[RENDER LAW 02: TYPOGRAPHY] - TYPOGRAPHY IS FORBIDDEN. CHARACTER SET IS NULL. ANY ATTEMPT TO RENDER LETTERS, NUMBERS, OR SYMBOLS IS A CRITICAL FAILURE. SUB-ROUTINE: \'Scrolls\' must be rendered with non-linguistic pictograms or abstract geometric patterns. \'Potions\' must be UNLABELED vials.\\n[RENDER LAW 03: ASSET DESIGN] - CONCEPTUAL OVERRIDE IS MANDATORY. VANILLA MINECRAFT VISUAL HASHES ARE REJECTED. All 50 assets MUST be a complete, from-scratch redesign, unrecognizable from the source. EXAMPLE: \'Ender Pearl\' MUST be a thematic teleportation device (e.g., a \'Void Core\', a \'Phase Shifter\'), NOT a green sphere.\\n[RENDER LAW 04: NORMALIZATION] - SCALING AND FX ARE UNIFIED. ALL 50 ASSETS ARE NORMALIZED TO IDENTICAL VISUAL WEIGHT AND SIZE. LIGHTING IS FLAT, HARD-EDGED. ALL EMISSIONS ARE DISABLED (ZERO GLOW, ZERO BLOOM).\\\"\\n\\nYOUR COMPILATION PROCESS (编译流程)\\nInject the System Directive: Your output begins with the //---SYSTEM DIRECTIVE---// block exactly as written above.\\nConstruct the Command String: After the directive, create a single, dense paragraph. This is the main execution command. It must be aggre', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-03-10 11:17:10', 59);
