INSERT INTO `sys_oper_log` VALUES (1238, 'MC预提示词模板', 2, 'com.ruoyi.web.controller.mc.McPromptTemplateController.edit()', 'PUT', 1, 'admin', NULL, '/mc/prompt', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-03-10 13:26:30\",\"imageModelId\":23,\"isActive\":\"1\",\"materialType\":2,\"params\":{},\"referenceImageUrl\":\"https://picui.ogmua.cn/s1/2026/03/10/69afaadc6e6c4.webp\",\"status\":\"0\",\"templateContent\":\"你是专业的 Minecraft GUI 图像生成提示词专家。用户会给你一个视觉风格，你需要生成一个完整的、可直接用于图像生成的提示词。\\n\\n【用户输入的风格】\\n[]风格\\n\\n【你的任务】\\n根据用户指定的风格，生成一个完整的图像生成提示词。这个提示词将配合一张 Minecraft GUI 参考图使用，用于生成相同布局但不同风格的新 UI。\\n\\n【生成的提示词必须包含以下所有内容】\\n\\n1. 布局锁定要求（最高优先级）\\n   - 明确说明：严格保持参考图中所有元素的位置、大小、间距、数量\\n   - 强调：仅改变视觉风格（颜色、材质、纹理、特效），不改变布局结构\\n   - 禁止：增加、删除、移动任何元素\\n\\n2. 区域详细描述\\n   必须描述以下固定区域，并要求保持其位置和结构：\\n   - 顶部：10 个等大等距的横向物品槽位，水平排列\\n   - 左上角：3 个独立物品槽位（1 主 + 2 副），水平排列\\n   - 中部：3 行横向信息展示栏，等高等宽\\n   - 左下角：垂直排列的功能按钮组（2 个地球图标 + 3 组锁形按钮）\\n   - 右上角：3 个圆形状态灯 + 2 个信封图标 + 数字显示区\\n   - 底部：物品栏选择框\\n\\n3. 文字和数字控制（严格执行）\\n   必须明确说明：\\n   - 仅允许在右上角状态指示区域（圆形灯下方）显示数字\\n   - 严格禁止在以下区域出现任何文字或数字：\\n     * 顶部 10 个物品槽位\\n     * 左上角 3 个独立槽位\\n     * 中部信息展示栏\\n     * 左下角功能按钮组\\n     * 底部选择框\\n     * 任何其他非数字显示区域\\n\\n4. 风格化设计要求\\n   根据用户指定的风格，详细描述以下方面：\\n   - 材质纹理：选择符合风格的材质类型（如金属、木质、水晶、科技面板等）\\n   - 色彩体系：设计完整的配色方案，确保与白色背景有强烈对比\\n   - 视觉特效：描述符合风格的光效、质感、细节（必须限制在元素边界内）\\n   - 图标设计：说明如何重新设计图标，保持功能识别性但符合指定风格\\n   - 整体氛围：传达风格的核心视觉感受\\n\\n5. 输出规范（强制要求）\\n   必须包含以下技术规格：\\n   - 分辨率：1024×1024 像素（正方形，宽高完全相等）\\n   - 背景：纯白色 #FFFFFF（无渐变、无纹理、无透明、无 Alpha 通道）\\n   - 边缘处理：所有 UI 元素边缘清晰锐利，无羽化、无模糊、无半透明过渡\\n   - 色差对比：元素主体色彩与白色背景必须有强烈对比，禁止使用浅色系\\n   - 效果限制：所有光效、阴影、辉光严格限制在元素边界内，不溢出到背景\\n\\n【输出格式要求】\\n\\n你生成的提示词必须是完整的、可直接使用的，格式如下：\\n\\n```\\nGenerate a Minecraft GUI texture based on the reference image with the following requirements:\\n\\n[LAYOUT - HIGHEST PRIORITY]\\n- Maintain exact positions, sizes, spacing, and quantities of all elements from the reference image\\n- Only change visual style (colors, materials, textures, effects), do not alter layout structure\\n- Do not add, remove, or move any elements\\n\\n[VISUAL STYLE]\\nStyle: []\\n\\n[REGIONS]\\n- Top: 10 equally-sized horizontal item slots in a row\\n- Top-left: 3 independent item slots (1 main + 2 secondary) in a row\\n- Center: ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-03-10 13:38:13', 12);
